    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further",
        "then", "once", "here", "there", "when", "where", "why", "how",
        "all", "each", "every", "both", "few", "more", "most", "other",
        "some", "such", "no", "nor", "not", "only", "own", "same", "so",
        "than", "too", "very", "can", "will", "just", "should", "now",
        "he", "she", "it", "they", "we", "you", "i", "me", "him", "her",
        "us", "them", "my", "your", "his", "its", "our", "their",
        "this", "that", "these", "those", "has", "have", "had", "do",
        "does", "did", "be", "been", "being", "if", "also", "about",
        "up", "would", "could", "which", "what", "who", "whom"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scoredSentences);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceRegex().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in WordRegex().Matches(sentence).Select(m => m.Value))
            {
                if (word.Length <= 2 || StopWords.Contains(word))
                    continue;

                frequencies.TryGetValue(word, out var count);
                frequencies[word] = count + 1;
            }
        }

        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = WordRegex().Matches(sentence).Select(m => m.Value).ToList();
        if (words.Count == 0)
            return 0;

        double score = words
            .Where(w => wordFrequencies.ContainsKey(w))
            .Sum(w => wordFrequencies[w]);

        // Normalize by sentence length to avoid bias toward longer sentences
        return score / words.Count;
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText, int maxSentences);
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummaryController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

